    // We need to find the smallest index i such that s[i] == s[n - i - 1].
    // The loop should iterate from i = 0 up to the midpoint of the string.
    // The condition s[i] == s[n - i - 1] is the requirement.
    // Since we are looking for the *smallest* i, we iterate i starting from 0.

    // The loop should go up to n-1, but if i >= n - i - 1, the indices overlap or cross.
    // We only need to check up to the point where i < n - i - 1, or i <= (n - 1 - i).
    // 2*i <= n - 1  => i <= (n - 1) / 2

    // Iterating i from 0 to Math.floor((n - 1) / 2) covers all unique pairs (i, n-i-1) where i <= n-i-1.
    // If i = n - i - 1 (middle element for odd length), it's also covered.

    for (let i = 0; i < n; i++) {
        const j = n - 1 - i;

        // We only need to check pairs where i <= j, as checking (i, j) is the same as checking (j, i)
        // and we are looking for the minimum i. If i > j, we have already checked this pair when the index was j.
        if (i > j) {
            // Since we are iterating i upwards, once i > j, all subsequent pairs will also have i > j.
            break;
        }

        if (s[i] === s[j]) {
            // Since we iterate i in increasing order, the first match we find is the smallest i.
            return i;
        }
    }

    // If no such index is found after checking all necessary pairs.
    return -1;
}

